DDL:
DROP TABLE IF EXISTS DIM_GEOGRAPHY CASCADE;
CREATE TABLE DIM_GEOGRAPHY (
	GEOGRAPHY_ID BIGINT PRIMARY KEY,
	DIST_CODE BIGINT,
	STATE_CODE BIGINT,
	STATE_NAME VARCHAR(30),
	DIST_NAME VARCHAR(100)
);

DROP TABLE IF EXISTS DIM_YEAR CASCADE;
CREATE TABLE DIM_YEAR (
	YEAR_ID BIGINT PRIMARY KEY,
	YEAR INTEGER
);

DROP TABLE IF EXISTS FACT_OILSEEDS_SUNFLOWER CASCADE;
CREATE TABLE FACT_OILSEEDS_SUNFLOWER (
	OILSEED_SUNFLOWER_ID BIGINT PRIMARY KEY,
	GEOGRAPHY_ID BIGINT,
	YEAR_ID BIGINT,
	SUNFLOWER_AREA_1000HA DOUBLE PRECISION,
	SUNFLOWER_PRODUCTION_1000TONS DOUBLE PRECISION,
	SUNFLOWER_YIELD_KG_PER_HA DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_PULSES_MINOR CASCADE;
CREATE TABLE FACT_PULSES_MINOR (
	PULSE_MINOR_ID BIGINT PRIMARY KEY,
	GEOGRAPHY_ID BIGINT,
	YEAR_ID BIGINT,
	MINOR_PULSES_AREA_1000HA DOUBLE PRECISION,
	MINOR_PULSES_PRODUCTION_1000TONS DOUBLE PRECISION,
	MINOR_PULSES_YIELD_KG_PER_HA DOUBLE PRECISION
);
